<template>
  <div class="customcallbackpage-content ls-content-wrapper">
    <div class="ls-title-lv1">自定义回调</div>
    <div class="ls-text ls-top-40">
      自定义回调是基于<span class="ls-textfocus">selfDefinedCallBackFn</span>实现的。<br />
      在HTML中给可落焦节点绑定对应的属性值（只能是<span class="ls-textfocus">String</span>），
      初始化时把相同的Key挂到<span class="ls-textfocus">selfDefinedCallBackFn</span>里，当用户触发操作时会命中对应的方法。
    </div>
    <div class="ls-text ls-top-20">
      需要注意的是：当某个方向键或返回键绑定了自定义回调时，
      该方向默认的回调（如<span class="ls-textfocus">cbFocusLeft</span>）不会再触发。
    </div>
    <div class="ls-title-lv2 ls-top-30">HTML</div>
    <CodeView :codeText="customCallbackHtmlCode" :codeType="'html'"></CodeView>
    <div class="ls-title-lv2 ls-top-30">初始化绑定</div>
    <CodeView :codeText="customCallbackJsCode" :codeType="'javascript'"></CodeView>
    <div class="ls-title-lv2 ls-top-30">示例中自定义的方法名</div>
    <TableView :tableData="customCallbackTableData" />
    <div class="ls-title-lv2 ls-top-30">回调数据</div>
    <TableView :tableData="callbackData" />
  </div>
</template>

<script>
import CodeView from '@/components/CodeView.vue';
import TableView from "@/components/TableView.vue";
import { customCallbackHtml, customCallbackJs } from '@/configData/customcallback/customCallbackData.js';
import customCallbackTableData from "@/configData/customcallback/customCallbackTableData.json";
import callbackData from "@/configData/callback/callbackTableData.json";

export default {
  name: 'CustomCallbackPage',
  components: {
    CodeView,
    TableView,
  },
  data() {
    return {
      customCallbackHtml,
      customCallbackJs,
      customCallbackTableData,
      callbackData,
    }
  },
  computed: {
    customCallbackHtmlCode() {
      return this.customCallbackHtml;
    },
    customCallbackJsCode() {
      return this.customCallbackJs;
    },
  }
}
</script>

